// App.js — connects ALL screens together

import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";

// Shared screens
import SplashScreen from "./screens/SplashScreen";
import RoleSelectScreen from "./screens/RoleSelectScreen";
import LoginScreen from "./screens/LoginScreen";

// Student screens
import SignupScreen from "./screens/SignupScreen";
import HomeScreen from "./screens/HomeScreen";

// Startup screens
import StartupSignupScreen from "./screens/StartupSignupScreen";
import StartupHomeScreen from "./screens/StartupHomeScreen";

import "./App.css";

// This catches any crash and shows a helpful error instead of blank screen
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{padding:"30px", fontFamily:"sans-serif", maxWidth:"420px", margin:"0 auto"}}>
          <div style={{background:"#FEF2F2", border:"1px solid #FCA5A5", borderRadius:"12px", padding:"20px"}}>
            <h2 style={{color:"#DC2626", marginBottom:"12px"}}>⚠️ App Error</h2>
            <p style={{color:"#7F1D1D", fontSize:"14px", marginBottom:"16px"}}>
              Something crashed. Most likely cause: <strong>Firebase config not set up yet.</strong>
            </p>
            <div style={{background:"white", borderRadius:"8px", padding:"14px", marginBottom:"16px"}}>
              <p style={{fontSize:"13px", color:"#444", marginBottom:"8px"}}><strong>Error message:</strong></p>
              <code style={{fontSize:"12px", color:"#DC2626", wordBreak:"break-all"}}>
                {this.state.error?.message || "Unknown error"}
              </code>
            </div>
            <p style={{fontSize:"13px", color:"#7F1D1D", marginBottom:"8px"}}><strong>Fix this by:</strong></p>
            <ol style={{fontSize:"13px", color:"#7F1D1D", paddingLeft:"20px", lineHeight:"1.8"}}>
              <li>Open <code>src/firebase/config.js</code></li>
              <li>Replace all "YOUR_..." placeholder values with your real Firebase config</li>
              <li>Save the file and refresh the browser</li>
            </ol>
            <button
              onClick={() => window.location.href = "/"}
              style={{marginTop:"16px", padding:"10px 20px", background:"#1D9E75",
                color:"white", border:"none", borderRadius:"8px", cursor:"pointer",
                fontSize:"14px", fontWeight:"500"}}
            >
              Try Again
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

function App() {
  return (
    <ErrorBoundary>
      <BrowserRouter>
        <Routes>
          {/* Shared */}
          <Route path="/" element={<SplashScreen />} />
          <Route path="/role-select" element={<RoleSelectScreen />} />
          <Route path="/login" element={<LoginScreen />} />

          {/* Student flow */}
          <Route path="/signup/student" element={<SignupScreen />} />
          <Route path="/home" element={<HomeScreen />} />

          {/* Startup flow */}
          <Route path="/signup/startup" element={<StartupSignupScreen />} />
          <Route path="/startup/home" element={<StartupHomeScreen />} />

          {/* Catch all unknown routes */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </BrowserRouter>
    </ErrorBoundary>
  );
}

export default App;
